public class MethodAnatomy {
    //  [modifier] [static] [return type] [name]  ([params])  { body }
    public  static  int          add      (int a, int b) { return a + b; }
    private static  void         print    (String s)     { System.out.println(s); }
    public  static  double       divide   (double x, double y) {
        if (y == 0) throw new ArithmeticException("Division by zero");
        return x / y;
    }

    // void return type: method does not return a value
    public static void greet(String name) {
        System.out.println("Hello, " + name);
        // return;  // optional: empty return statement is valid in void methods
    }

    public static void main(String[] args) {
        int result = add(3, 5);         // result = 8
        print("Result: " + result);     // Result: 8
        System.out.println(divide(10.0, 4.0));  // 2.5
        greet("Ashik");                 // Hello, Ashik
    }
}

public class PassByValue {
    // Case 1: Primitive — change is local only
    static void tryDouble(int x) {
        x = x * 2;
        System.out.println("Inside: " + x);  // 20
    }

    // Case 2: Object (array) — contents can be modified
    static void fillFirst(int[] arr, int val) {
        arr[0] = val;  // Modifies the original array's element
        arr = new int[]{999}; // Only changes local ref — caller unaffected
    }

    // Case 3: String — immutable, "modification" creates new object
    static void tryAppend(String s) {
        s = s + " World"; // Creates a new String; original unchanged
        System.out.println("Inside: " + s);  // Inside: Hello World
    }

    public static void main(String[] args) {
        // Case 1
        int n = 10;
        tryDouble(n);
        System.out.println("After: " + n);    // After: 10 (unchanged)

        // Case 2
        int[] arr = {1, 2, 3};
        fillFirst(arr, 99);
        System.out.println(arr[0]);  // 99 (element changed)
        System.out.println(arr.length);  // 3 (still original array, not {999})

        // Case 3
        String str = "Hello";
        tryAppend(str);
        System.out.println(str);  // Hello (unchanged)
    }
}

public class Overloading {
    static String describe(int x) {
        return "int: " + x;
    }
    static String describe(double x) {
        return "double: " + x;
    }
    static String describe(int x, int y) {
        return "two ints: " + x + ", " + y;
    }
    static String describe(String s) {
        return "String: " + s;
    }
    static String describe(Object o) {
        return "Object: " + o;
    }

    public static void main(String[] args) {
        System.out.println(describe(5));        // int: 5
        System.out.println(describe(5.0));      // double: 5.0
        System.out.println(describe(5L));       // Object: 5  (long→no exact match→Object)
        System.out.println(describe(3, 4));     // two ints: 3, 4
        System.out.println(describe("hello")); // String: hello
        System.out.println(describe(3.0f));     // double: 3.0  (float→widened to double)

        // Widening: byte < short < int < long < float < double
        byte b = 10;
        System.out.println(describe(b));  // int: 10  (byte widens to int)
    }
}

public class Varargs {
    // int... nums behaves like int[] nums inside the method
    static int sum(int... nums) {
        int total = 0;
        for (int n : nums) total += n;
        return total;
    }

    // Varargs combined with required params
    static void printAll(String label, int... values) {
        System.out.print(label + ": ");
        for (int v : values) System.out.print(v + " ");
        System.out.println();
    }

    // This overload takes priority over varargs for a single int
    static int sum(int a) {
        System.out.print("(single) ");
        return a;
    }

    public static void main(String[] args) {
        System.out.println(sum());          // (no single-int match) 0
        System.out.println(sum(5));         // (single) 5  — exact match preferred
        System.out.println(sum(1, 2, 3));   // 6
        System.out.println(sum(new int[]{10, 20})); // 30 — can pass array explicitly

        printAll("Scores", 85, 92, 78);    // Scores: 85 92 78
        printAll("Empty");                  // Empty: (nothing)
    }
}

public class ScopeDemo {
    static int x = 100;  // static field — class scope

    static void test() {
        int x = 5;  // local variable shadows static field
        System.out.println(x);          // 5  (local)
        System.out.println(ScopeDemo.x); // 100 (static field via class name)

        {
            // int x = 10; // COMPILE ERROR: x already defined in enclosing scope
            int y = 20;  // y is new — valid here
            System.out.println(y);  // 20
        }
        // System.out.println(y); // COMPILE ERROR: y out of scope
    }

    static int countUp(int start, int end) {
        int count = 0;  // must initialize — no default for locals
        for (int i = start; i <= end; i++) {
            count++;  // i is only valid inside the for loop
        }
        // System.out.println(i); // ERROR: i is out of scope
        return count;
    }

    public static void main(String[] args) {
        test();
        System.out.println(countUp(3, 7));  // 5
    }
}

public class Recursion {
    static int factorial(int n) {
        if (n <= 1) return 1;        // base case
        return n * factorial(n - 1); // recursive case
    }

    static void countdown(int n) {
        if (n < 0) return;           // base case
        System.out.print(n + " ");
        countdown(n - 1);            // recursive call AFTER print
    }

    static void countup(int n, int max) {
        if (n > max) return;
        countup(n + 1, max);         // recursive call BEFORE print
        System.out.print(n + " ");
    }

    public static void main(String[] args) {
        System.out.println(factorial(5));    // 120
        countdown(4);   System.out.println();  // 4 3 2 1 0
        countup(1, 4);  System.out.println();  // 4 3 2 1  (reversed!)
    }
}

