// Write a class Calculator with overloaded add() methods:
// 1. add(int a, int b) → returns int sum
// 2. add(double a, double b) → returns double sum
// 3. add(int a, int b, int c) → returns int sum of three
// 4. add(String a, String b) → returns concatenated String
// 5. add(int... nums) → returns int sum of any number of ints
// In main, call each version and verify it selects the correct overload.
// Make sure add(5) uses the varargs version (not a single-int version).

sections.solution:
public class Calculator {
    static int add(int a, int b) {
        System.out.print("(int,int) ");
        return a + b;
    }
    static double add(double a, double b) {
        System.out.print("(double,double) ");
        return a + b;
    }
    static int add(int a, int b, int c) {
        System.out.print("(int,int,int) ");
        return a + b + c;
    }
    static String add(String a, String b) {
        System.out.print("(String,String) ");
        return a + b;
    }
    static int add(int... nums) {
        System.out.print("(varargs) ");
        int total = 0;
        for (int n : nums) total += n;
        return total;
    }

    public static void main(String[] args) {
        System.out.println(add(3, 4));           // (int,int) 7
        System.out.println(add(1.5, 2.5));       // (double,double) 4.0
        System.out.println(add(1, 2, 3));        // (int,int,int) 6
        System.out.println(add("Hi ", "World")); // (String,String) Hi World
        System.out.println(add(5));              // (varargs) 5
        System.out.println(add(1, 2, 3, 4, 5));  // (varargs) 15 — 3-arg only goes to 3 ints
    }
}
